// app/login/page.tsx
'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';

const LOGO_SRC = 'data:image/png;base64,';

export default function LoginPage() {
  const router = useRouter();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const signIn = async () => {
    setLoading(true);
    setError(null);
    const supabase = createClient();
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    setLoading(false);
    if (error) { setError(error.message); return; }
    router.push('/');
    router.refresh();
  };

  return (
    <div style={{ display: 'flex', minHeight: '100vh', alignItems: 'center', justifyContent: 'center', background: '#0A1628', padding: '0 16px' }}>
      <div style={{ width: '100%', maxWidth: 360, background: '#0d1e35', border: '1px solid rgba(61,155,196,0.25)', borderRadius: 12, padding: 32, display: 'flex', flexDirection: 'column', gap: 20 }}>
        <div style={{ display: 'flex', justifyContent: 'center' }}>
          <img src={LOGO_SRC} alt="AUK Marine & Mining" style={{ width: 160, height: 'auto', objectFit: 'contain' }} />
        </div>
        <div style={{ textAlign: 'center' }}>
          <h1 style={{ fontSize: 16, fontWeight: 500, color: '#C6DDEC', margin: 0 }}>Port Capacity Platform</h1>
          <p style={{ fontSize: 14, color: '#8EC5DC', marginTop: 4 }}>Sign in to continue</p>
        </div>
        {error && (
          <div style={{ borderRadius: 8, padding: '8px 12px', fontSize: 14, border: '1px solid rgba(220,50,50,0.4)', background: 'rgba(220,50,50,0.1)', color: '#f87171' }}>
            {error}
          </div>
        )}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          <input type="email" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)}
            style={{ width: '100%', borderRadius: 6, padding: '8px 12px', fontSize: 14, background: '#0a1628', border: '1px solid rgba(61,155,196,0.3)', color: '#C6DDEC', outline: 'none', boxSizing: 'border-box' }} />
          <input type="password" placeholder="Password" value={password} onChange={e => setPassword(e.target.value)} onKeyDown={e => e.key === 'Enter' && signIn()}
            style={{ width: '100%', borderRadius: 6, padding: '8px 12px', fontSize: 14, background: '#0a1628', border: '1px solid rgba(61,155,196,0.3)', color: '#C6DDEC', outline: 'none', boxSizing: 'border-box' }} />
        </div>
        <button onClick={signIn} disabled={loading || !email || !password}
          style={{ width: '100%', borderRadius: 6, padding: '8px 16px', fontSize: 14, fontWeight: 600, cursor: 'pointer', border: 'none', background: loading || !email || !password ? 'rgba(61,155,196,0.4)' : '#3D9BC4', color: '#ffffff' }}>
          {loading ? 'Signing in…' : 'Sign in'}
        </button>
      </div>
    </div>
  );
}
